package main

import "fmt"

func spiralMatrix(data [][]int) []int {
    if len(data) == 0 {
        return nil
    }

    result := []int{}
    top, bottom, left, right := 0, len(data)-1, 0, len(data[0])-1

    for top <= bottom && left <= right {
        for i := left; i <= right; i++ {
            result = append(result, data[top][i])
        }
        top++

        for i := top; i <= bottom; i++ {
            result = append(result, data[i][right])
        }
        right--

        if top <= bottom {
            for i := right; i >= left; i-- {
                result = append(result, data[bottom][i])
            }
            bottom--
        }

        if left <= right {
            for i := bottom; i >= top; i-- {
                result = append(result, data[i][left])
            }
            left++
        }
    }

    return result
}

func main() {
    matrix := [][]int{
        {1, 2, 3},
        {4, 5, 6},
        {7, 8, 9},
    }
    fmt.Println(spiralMatrix(matrix)) // Output: [1 2 3 6 9 8 7 4 5]
}

